import folderIcon from "../static/folder.jpeg";
import "../static/PageModal.css";
import GlobalContext from "../context/GlobalContext";
import { useQuery } from "@apollo/client";
import { useMutation } from "@apollo/react-hooks";
import gql from "graphql-tag";

import { Fragment, useContext, useEffect, useState } from "react";
import { AuthContext } from "../context/auth";
import dayjs from "dayjs";
import { useForm } from "../utils/hooks";
import { FETCH_TODOS_QUERY } from "../utils/querys";

export default function PageView() {
  const { modalObj, setModalObj, db, setDb } = useContext(GlobalContext);
  const nowPage = modalObj.page;
  console.log(nowPage);
  const nowPageDate = nowPage.date.split(" ");
  console.log(nowPageDate);
  const [pageDate, setPageDate] = useState(
    nowPageDate[0] || dayjs().format("YYYY-MM-DD")
  );
  const [pageTime, setPageTime] = useState(
    nowPageDate.length === 2 ? nowPageDate[1] : dayjs().format("HH:mm")
  );
  const [isCheckedTime, setIsCheckedTime] = useState(nowPageDate.length !== 1);
  const [prntTitle, setPrntTitle] = useState("");
  const [childTitle, setChildTitle] = useState("");

  const { onChange, onSubmit, values } = useForm(updatePageCb, {
    date: nowPage.date,
    title: nowPage.title,
    pageType: nowPage.pageType,
    text: nowPage.text,
    pageId: nowPage.id,
  });

  async function updatePageCb() {
    values.date = isCheckedTime ? pageDate + " " + pageTime : pageDate;
    setModalObj({ type: "", isMutation: true });
  }

  return (
    <div className="bgModal">
      <form
        action=""
        method="post"
        className="pageDateModal"
        onSubmit={onSubmit}
      >
        <header>
          <button
            className="close"
            onClick={() => setModalObj({ type: "" })}
          ></button>
        </header>
        <main>
          <div className="title">
            {values.pageType === "todo" && <input type="checkbox" />}
            <input
              type="text"
              name="title"
              value={values.title}
              onChange={onChange}
              placeholder="TITLE"
              className="titleInput"
              required
            />
          </div>

          <div className="when">
            <input
              type="date"
              name="date"
              value={pageDate}
              className="dateInput"
              onChange={(e) => setPageDate(e.target.value)}
            />
            {isCheckedTime && (
              <input
                type="time"
                name=""
                value={pageTime}
                onChange={(e) => setPageTime(e.target.value)}
                className="listTime"
              />
            )}
            <label className="checkTime">
              <input
                type="checkbox"
                checked={isCheckedTime}
                onChange={(e) => setIsCheckedTime(e.target.checked)}
              />
              time
            </label>
          </div>

          <textarea
            type="text"
            name="text"
            value={values.text}
            onChange={onChange}
            placeholder="Contents..."
            className="textInput"
          />
        </main>
        <footer>
          <div className="PageTodoType">
            <label>
              <input
                type="radio"
                name="pageType"
                value="page"
                onChange={onChange}
                defaultChecked
              />
              Page
            </label>
            <label>
              <input
                type="radio"
                name="pageType"
                value="todo"
                onChange={onChange}
              />
              Todo
            </label>
          </div>
          <button id="save" type="submit">
            SAVE
          </button>
        </footer>
      </form>
    </div>
  );
}

const UPDATE_PAGE = gql`
  mutation UpdatePage(
    $date: String!
    $title: String!
    $userId: ID!
    $pageId: ID!
    $parentInput: [ParentInput]
    $childInput: [ChildInput]
    $pageType: String!
  ) {
    updatePage(
      pageInput: {
        date: $date
        title: $title
        userId: $userId
        pageId: $pageId
        parentInput: $parentInput
        childInput: $childInput
        pageType: $pageType
      }
    ) {
      id
      title
      date
      isDone
      parent {
        parentId
        parentTitle
        parentDate
      }
      childs {
        childId
        childDate
        childTitle
      }
      text
      createdAt
      pageType
    }
  }
`;
