import { Fragment, useContext, useEffect } from "react";
import { useQuery } from "@apollo/client";
import { useMutation } from "@apollo/react-hooks";

import gql from "graphql-tag";
import GlobalContext from "../context/GlobalContext";
import { AuthContext } from "../context/auth";
import { useForm } from "../utils/hooks";
import dayjs from "dayjs";
import { FETCH_TODOS_QUERY } from "../utils/querys";

export default function PageList({ pageDate }) {
  const { pageMode, modalObj, setModalObj, db, setDb } =
    useContext(GlobalContext);
  let pageList = [];

  if (db) {
    pageList = db.filter(
      ({ date, pageType }) =>
        dayjs(date).format("YYYY-MM-DD") ===
          dayjs(pageDate).format("YYYY-MM-DD") &&
        (pageMode === "todo" ? pageType === pageMode : true)
    );
  }

  const { onChange, onSubmit, values } = useForm(deletePageCb, {
    pageId: dayjs().toISOString(),
  });

  function deletePageCb() {
    setDb(db.filter((p) => p.id !== values.pageId));
  }

  async function onDelete(e) {
    await onChange(e);
    onSubmit(e);
  }

  function PrntPageCell({ page }) {
    const nowPage = db.find(({ id }) => id === page.parentId);
    return (
      <div className={"prntPageCell " + "pageCell"}>
        <p onClick={() => setModalObj({ type: "pageView", page: nowPage })}>
          {page.parentTitle}
        </p>
        <button
          name="pageId"
          value={page.parentId}
          onClick={onDelete}
          type="submit"
        >
          -
        </button>
        <button
          onClick={() =>
            setModalObj({
              date: pageDate,
              parent: [
                {
                  parentId: page.parentId,
                  parentDate: page.parentDate,
                  parentTitle: page.parentTitle,
                },
              ],
              type: "page",
            })
          }
        >
          +
        </button>
      </div>
    );
  }

  function PageCell({ page }) {
    return (
      <div className="pageCell">
        <p onClick={() => setModalObj({ type: "pageView", page })}>
          {page.title}
        </p>
        <button name="pageId" value={page.id} onClick={onDelete} type="submit">
          -
        </button>
        <button
          onClick={() =>
            setModalObj({
              date: pageDate,
              parent: [
                {
                  parentId: page.id,
                  parentDate: page.date,
                  parentTitle: page.title,
                },
              ],
              type: "page",
            })
          }
        >
          +
        </button>
      </div>
    );
  }

  return (
    <div className="pageList">
      {pageList.length !== 0 &&
        pageList.map((page, i) => (
          <div className="familyPage" key={i}>
            <PageCell page={page} />
          </div>
        ))}
    </div>
  );
}

const DELETE_PAGE = gql`
  mutation DeletePage($userId: ID!, $pageId: ID!) {
    deletePage(userId: $userId, pageId: $pageId) {
      id
      userId
      username
      pages {
        id
        title
        date
        isDone
        parent {
          parentId
          parentTitle
          parentDate
        }
        childs {
          childId
          childDate
          childTitle
        }
        text
        pageType
        createdAt
      }
    }
  }
`;
