import "../static/Nav.css";
import React, { useContext, useState } from "react";
import { AuthContext } from "../context/auth";
import { useNavigate } from "react-router-dom";
import GlobalContext from "../context/GlobalContext";
import dayjs from "dayjs";
import magn from "../static/magn.png";

export default function Nav() {
  const user = useContext(AuthContext);
  const navigate = useNavigate();
  const { pageMode, setPageMode } = useContext(GlobalContext);

  function logout() {
    user.logout();
    navigate("month/" + dayjs().format("YYYY/MM"));
  }

  return (
    <div className="nav">
      <div className="nav_left">
        <a href="/" className="mainLogo">
          DayMonth
        </a>
        <div className="searchBar">
          <div className="searchIcon"></div>
          <input
            className="search"
            type="text"
            placeholder="Search for events"
            style={{ color: "#7b417b" }}
          />
          <img className="searchImg" src={magn}></img>
        </div>
      </div>
      <div className="nav_right">
        {user.user ? (
          <div onClick={logout}>Logout</div>
        ) : (
          <React.Fragment>
            <div onClick={() => navigate("/login")}>Login</div>
            <div onClick={() => navigate("/register")}>Register</div>
          </React.Fragment>
        )}

        <div
          onClick={() => setPageMode(pageMode === "page" ? "todo" : "page")}
          className="modeSwitch"
        >
          {pageMode}
        </div>
      </div>
    </div>
  );
}
