import React from "react";
import { Fragment, useContext } from "react";
import GlobalContext from "../context/GlobalContext";
import PageList from "./PageList";
import { useNavigate, useParams } from "react-router-dom";
import "../static/DayView.css";

function DayView() {
  const { dayViewDate, setModalObj } = useContext(GlobalContext);
  const navigate = useNavigate();
  const params = useParams();
  let year = Number(params.year);
  let month = Number(params.month);

  return (
    <Fragment>
      <div className="cal_day_header">
        <p
          className="month"
          onClick={() => {
            navigate(`/month/${year}/${month}`);
          }}
        >
          {dayViewDate.format("YYYY ") +
            dayViewDate.format("MMM").toUpperCase() +
            dayViewDate.format(" DD")}
        </p>
      </div>
      <div className="cal_day_body">
        <PageList pageDate={dayViewDate} />
        <div className="navBox">
          <button
            onClick={() =>
              setModalObj({
                date: dayViewDate.format("YYYY-MM-DD"),
                type: "page",
              })
            }
          >
            +
          </button>
          <button onClick={() => navigate(-1)}>&#60;</button>
        </div>
      </div>
    </Fragment>
  );
}

export default DayView;
